                <label htmlFor={`rotFeg-${item.id}`} style={{fontSize:10.5,color:"#b45309",cursor:"pointer",fontWeight:item.rotFeg?700:400}}>FEG Upcharge — ${72}/tray{item.rotFeg&&item.rotQ>1?` × ${item.rotQ} = $${72*item.rotQ}`:""}</label>
